import React, { useState, useRef, useCallback } from 'react';
import PreRecord from './PreRecord';
import WhileRecord from './WhileRecord';
import PlayBack from './PlayBack';
import Share from './Share';
import SaveConfirm from './SaveConfirm';

function RecordPage() {
  const [screen, setScreen] = useState('pre');
  const [recordedTime, setRecordedTime] = useState(0);
  const [audioBlob, setAudioBlob] = useState(null);
  const [error, setError] = useState('');
  const [analyserNode, setAnalyserNode] = useState(null);

  const mediaRecorderRef = useRef(null);
  const audioContextRef = useRef(null);
  const chunksRef = useRef([]);
  const streamRef = useRef(null);

  const startRecording = async () => {
    try {
      setError('');
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 2048;
      source.connect(analyser);
      audioContextRef.current = audioCtx;
      setAnalyserNode(analyser);

      const recorder = new MediaRecorder(stream);
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        setAudioBlob(blob);
      };

      mediaRecorderRef.current = recorder;
      recorder.start(100);
      setScreen('while');
    } catch (err) {
      setError('We need permission to use your microphone. Please allow access and try again.');
      console.error('Recording error:', err);
    }
  };

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop());
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    setAnalyserNode(null);
  }, []);

  const handleRecord = () => startRecording();

  const handlePause = (elapsed) => {
    stopRecording();
    setRecordedTime(elapsed);
    setScreen('playback');
  };

  const handleSave = (elapsed) => {
    stopRecording();
    if (elapsed !== undefined) setRecordedTime(elapsed);
    setScreen('share');
  };

  const handleContinue = () => startRecording();

  const handleRestart = () => {
    setRecordedTime(0);
    setAudioBlob(null);
    setScreen('pre');
  };

  const handleShare = async () => {
    if (audioBlob) {
      try {
        const formData = new FormData();
        formData.append('audio', audioBlob, 'recording.webm');
        await fetch('http://localhost:5000/api/recordings', {
          method: 'POST',
          body: formData,
        });
      } catch (err) {
        console.error('Upload failed:', err);
      }
    }
    setScreen('save');
  };

  const handleNew = () => {
    setRecordedTime(0);
    setAudioBlob(null);
    setScreen('pre');
  };

  switch (screen) {
    case 'pre':
      return <PreRecord onRecord={handleRecord} error={error} />;
    case 'while':
      return (
        <WhileRecord
          analyserNode={analyserNode}
          onPause={handlePause}
          onSave={handleSave}
          startTime={recordedTime}
        />
      );
    case 'playback':
      return (
        <PlayBack
          audioBlob={audioBlob}
          currentTime={recordedTime}
          onContinue={handleContinue}
          onRestart={handleRestart}
          onSave={() => handleSave(recordedTime)}
        />
      );
    case 'share':
      return (
        <Share
          audioBlob={audioBlob}
          duration={recordedTime}
          onShare={handleShare}
          onNew={handleNew}
        />
      );
    case 'save':
      return (
        <SaveConfirm
          audioBlob={audioBlob}
          duration={recordedTime}
          onNew={handleNew}
        />
      );
    default:
      return <PreRecord onRecord={handleRecord} error={error} />;
  }
}

export default RecordPage;
